import os
import sys
import shutil
import zipfile
import tarfile
import subprocess

def create_backup(source_dir, backup_format):
    if not os.path.exists(source_dir):
        print(f"Source directory '{source_dir}' does not exist.")
        return
    
    backup_filename = os.path.basename(os.path.normpath(source_dir)) + f".{backup_format}"
    backup_path = os.path.join(os.getcwd(), backup_filename)

    if backup_format == 'zip':
        with zipfile.ZipFile(backup_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(source_dir):
                for file in files:
                    zipf.write(os.path.join(root, file), os.path.relpath(os.path.join(root, file), source_dir))
    
    elif backup_format == 'tar.gz':
        with tarfile.open(backup_path, 'w:gz') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    
    elif backup_format == 'tar.bz2':
        with tarfile.open(backup_path, 'w:bz2') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    
    elif backup_format == '7z':
        try:
            subprocess.run(['7z', 'a', backup_path, source_dir], check=True)
        except Exception as e:
            print("7z compression failed:", e)
            return
    else:
        print("Unsupported backup format.")
        return

    print(f"Backup created: {backup_path}")

if __name__ == '__main__':
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <backup_format>")
